<template>
	<view>
		<u-navbar title="实名认证"></u-navbar>
		<template v-if="userCertify">
			<view class="">
				<u-cell-group>
					<u-cell-item title="姓名" :value="certifyForm.real_name" :arrow="false"></u-cell-item>
					<u-cell-item title="身份证" :value="certifyForm.card_no" :arrow="false"></u-cell-item>
					<u-cell-item title="手机号码" :value="certifyForm.mobile" :arrow="false"></u-cell-item>
				</u-cell-group>
			</view>
		</template>
		<template v-else>
			<view class="padding20 bg-white">
				<view class="tip-box warning" v-if="certifyTip">
					<u-parse :html="certifyTip" :selectable="true" :show-with-animation="true"></u-parse>
				</view>

				<u-form :model="ruleForm" ref="uForm" label-width="160">
					<u-form-item label="认证方式" prop="certify_type" v-if="certifyList.length > 1">
						<!-- <certify-radio v-model="ruleForm.certify_type" :list="certifyList" /> -->
						<u-radio-group v-model="ruleForm.certify_type">
							<u-radio v-for="(item, index) in certifyList" :key="index" :name="item.type">
								{{item.name}}
							</u-radio>
						</u-radio-group>
					</u-form-item>
					<u-form-item label="姓名" prop="real_name">
						<u-input v-model="ruleForm.real_name" placeholder="请输入姓名" />
					</u-form-item>
					<u-form-item label="身份证" prop="card_no">
						<u-input v-model="ruleForm.card_no" placeholder="请输入身份证" />
					</u-form-item>
					<u-form-item label="手机号码" prop="mobile">
						<text>{{this.userinfo.mobile}}</text>
					</u-form-item>
				</u-form>
				<u-button @click="submit">提交认证信息</u-button>
			</view>
		</template>
		<slideCode v-if="slideCode[0].show" :session_id="session_id[0]" @close="slideCode[0].show = false"
			@success="$slideCode_success(0, $event)"></slideCode>
		<qrcode-dialog ref="qrcode-dialog" @fail="handelCertifyFail" @success="handelCertifySuccess" />
	</view>
</template>

<script>
	import slideCode from '@/components/slideCode.vue'
	import QrcodeDialog from './components/QrcodeDialog'

	export default {
		components: {
			slideCode,
			'qrcode-dialog': QrcodeDialog
		},
		data() {
			return {
				userCertify: false,
				certifyTip: '',
				certifyForm: {
					real_name: '',
					card_no: '',
					mobile: '',
					type: 1
				},
				ruleForm: {
					certify_type: '', //认证方式
					card_no: '',
					real_name: '',
					type: 1
				},
				rules: {
					certify_type: [{
						required: true,
						message: '请选择认证方式',
						trigger: 'change'
					}],
					card_no: [{
						required: true,
						message: '请输入身份证号码',
						trigger: 'blur'
					}],
					real_name: [{
						required: true,
						message: '请输入真实姓名',
						trigger: 'blur'
					}]
				},
				certifyList: [], // 认证方式列表

				slideCode: [{
					show: false
				}],
				session_id: [], //会自动生成的

				needCertify: false,
				certifyMoney: 0
			}
		},
		computed: {
			currCertify() {
				return this.certifyList.find(
					(item) => item.type == this.ruleForm.certify_type
				)
			}
		},
		onShow() {
			this.fetchData()
		},
		onLoad() {
			this.$slideCode_init(0); //初始化图形滑块			
		},
		onUnload() {

		},
		onReady() {
			this.$refs.uForm.setRules(this.rules);
		},
		methods: {
			$getRandomNunber(start, end) {
				return Math.floor(Math.random() * (end - start) + start)
			},
			$slideCode_init(index) {
				this.session_id[index] = this.$getRandomNunber(0, 999999999); //唯一id
				this.slideCode[index].yanzheng = false; //图形验证码是否验证通过
				this.slideCode[index].x = 0 //图形验证码的水平偏移值
			},
			async $slideCode_success(index, data) {
				this.slideCode[index].yanzheng = true //验证通过
				this.slideCode[index].x = data.x //偏移值
				const {
					url,
					return_type,
				} = await this.save()
				if (url) {
					if (return_type == 3) {
						this.$util.openAppUrl(url)
					}
					this.$refs['qrcode-dialog'].show({
						url,
						...this.currCertify
					})
				} else {
					this.$util.msg('认证成功')
					this.fetchData()
				}
			},
			async fetchData() {
				const {
					certify_tip,
					user_certify,
					mobile,
					card_no,
					real_name,
					type_config,
					need_certify,
					certify_money
				} = await this.$u.api.userGetCertify()
				if (!mobile) {
					this.$util.on('/pages/index/index')
					return
				}

				this.userCertify = user_certify
				this.certifyTip = certify_tip
				this.certifyForm.mobile = mobile
				this.certifyForm.card_no = card_no
				this.certifyForm.real_name = real_name
				this.certifyList = type_config
				if (type_config.length) {
					this.ruleForm.certify_type = type_config[0].type
				}
				this.needCertify = need_certify || false
				this.certifyMoney = certify_money || 0

				// this.needCertify = true
				// this.certifyMoney = 1
			},
			submit() {
				this.$refs.uForm.validate(async (valid) => {
					if (valid) {
						console.log('验证通过');
						if (this.needCertify) {
							// this.$refs['certify-popup'].showEdit(this.certifyMoney)
							this.$Router.push({
								name: 'certify_settle',
								params: {
									form: this.ruleForm,
									certifyMoney: this.certifyMoney,
									currCertify: this.currCertify
								}
							})
						} else {
							this.slideCode[0].show = true
						}
					} else {
						console.log('验证失败');
					}
				})

			},
			async save() {
				const {
					return_type,
					url
				} = await this.$u.api.userCertify(Object.assign(this.ruleForm, {
					session: this.session_id[0]
				}))
				return {
					return_type,
					url
				}
			},
			// 三方认证成功回调
			handelCertifySuccess({
				msg
			}) {
				this.$util.msg(msg)
				this.fetchData()
			},
			// 三方认证失败回调
			handelCertifyFail({
				msg
			}) {
				this.$util.msg(msg)
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.tip-box {
		display: flex;
		flex-direction: row;
		align-items: center;
		padding: 8px 15px;
		border-radius: 4px;
		position: relative;
		transition: all 0.3slinear;
		border: 1px solid #fff;
	}

	.tip-box.warning {
		border-color: #fcbd71;
		background-color: #fdf6ec;
	}
</style>